+// ─── Status effect drawing ────────────────────────────────────────────────
+
+function drawStatusEffect(
+  ctx: CanvasRenderingContext2D,
+  x: number,
+  y: number,
+  status: string,
+  frame: number,
+  scale: number,
+) {
+  const size = 16 * scale;
+  switch (status) {
+    case 'Idle': {
+      // subtle pulsing white glow (opacity oscillates 0.1-0.3)
+      const opacity = 0.2 + 0.1 * Math.sin(frame * 0.3 * Math.PI);
+      ctx.save();
+      ctx.shadowColor = `rgba(255,255,255,${opacity.toFixed(3)})`;
+      ctx.shadowBlur = 8 * scale;
+      ctx.strokeStyle = `rgba(255,255,255,${opacity.toFixed(3)})`;
+      ctx.lineWidth = 2 * scale;
+      ctx.strokeRect(x - 2 * scale, y - 2 * scale, size + 4 * scale, size + 4 * scale);
+      ctx.restore();
+      break;
+    }
+    case 'Working': {
+      // golden sparkle particles around character
+      const sparkleCount = 6;
+      ctx.save();
+      for (let i = 0; i < sparkleCount; i++) {
+        const angle = ((frame * 0.1 + i / sparkleCount) * 2 * Math.PI) % (2 * Math.PI);
+        const radius = 10 * scale;
+        const px = x + size / 2 + Math.cos(angle) * radius;
+        const py = y + size / 2 + Math.sin(angle) * radius;
+        const sparkleSize = 2 * scale + Math.sin(frame * 0.3 + i) * scale;
+        const opacity = 0.5 + 0.5 * Math.sin(frame * 0.3 + i);
+        ctx.fillStyle = `rgba(255,215,0,${opacity.toFixed(3)})`; // gold color
+        ctx.beginPath();
+        ctx.moveTo(px, py - sparkleSize);
+        ctx.lineTo(px + sparkleSize * 0.3, py - sparkleSize * 0.3);
+        ctx.lineTo(px + sparkleSize, py);
+        ctx.lineTo(px + sparkleSize * 0.3, py + sparkleSize * 0.3);
+        ctx.lineTo(px, py + sparkleSize);
+        ctx.lineTo(px - sparkleSize * 0.3, py + sparkleSize * 0.3);
+        ctx.lineTo(px - sparkleSize, py);
+        ctx.lineTo(px - sparkleSize * 0.3, py - sparkleSize * 0.3);
+        ctx.closePath();
+        ctx.fill();
+      }
+      ctx.restore();
+      break;
+    }
+    case 'Reviewing': {
+      // magnifying glass icon above head
+      const iconX = x + size / 2;
+      const iconY = y - 10 * scale;
+      ctx.save();
+      ctx.strokeStyle = '#444';
+      ctx.lineWidth = 2 * scale;
+      ctx.fillStyle = 'rgba(200,200,200,0.8)';
+      // circle lens
+      ctx.beginPath();
+      ctx.arc(iconX, iconY, 6 * scale, 0, 2 * Math.PI);
+      ctx.fill();
+      ctx.stroke();
+      // handle
+      ctx.beginPath();
+      ctx.moveTo(iconX + 4 * scale, iconY + 4 * scale);
+      ctx.lineTo(iconX + 10 * scale, iconY + 10 * scale);
+      ctx.stroke();
+      ctx.restore();
+      break;
+    }
+    case 'Stalled': {
+      // red pulsing outline
+      const opacity = 0.3 + 0.4 * Math.abs(Math.sin(frame * 0.2 * Math.PI));
+      ctx.save();
+      ctx.strokeStyle = `rgba(255,0,0,${opacity.toFixed(3)})`;
+      ctx.lineWidth = 3 * scale;
+      ctx.shadowColor = `rgba(255,0,0,${opacity.toFixed(3)})`;
+      ctx.shadowBlur = 10 * scale;
+      ctx.strokeRect(x - 3 * scale, y - 3 * scale, size + 6 * scale, size + 6 * scale);
+      ctx.restore();
+      break;
+    }
+    case 'Failed': {
+      // dark gray desaturation overlay
+      ctx.save();
+      ctx.fillStyle = 'rgba(50,50,50,0.5)';
+      ctx.fillRect(x, y, size, size);
+      ctx.globalCompositeOperation = 'saturation';
+      ctx.fillStyle = 'rgba(0,0,0,0.5)';
+      ctx.fillRect(x, y, size, size);
+      ctx.restore();
+      break;
+    }
+  }
+}
